previewCss:
.darma-loader-skeleton-line {
  display: grid;
  gap: 10px;
  width: 138px;
}
.darma-loader-skeleton-line i {
  display: block;
  height: 12px;
  border-radius: 999px;
  background: linear-gradient(90deg, color-mix(in srgb, var(--loader-color, #6366f1) 12%, transparent), color-mix(in srgb, var(--loader-color, #6366f1) 32%, transparent), color-mix(in srgb, var(--loader-color, #6366f1) 12%, transparent));
  background-size: 220% 100%;
  animation: darma-loader-skeleton-line-shimmer 1.1s linear infinite;
}
.darma-loader-skeleton-line i:nth-child(2) { width: 82%; }
.darma-loader-skeleton-line i:nth-child(3) { width: 58%; }
@keyframes darma-loader-skeleton-line-shimmer {
  to { background-position: -220% 0; }
}

